  1	import * as React from 'react';
  2	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
  3	import StaticDropdown from '@odf/shared/dropdown/StaticDropdown';
  4	import { FormGroupController } from '@odf/shared/form-group-controller';
  5	import { SecretModel } from '@odf/shared/models';
  6	import { getName } from '@odf/shared/selectors';
  7	import { SecretKind } from '@odf/shared/types';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { Control } from 'react-hook-form';
 10	import {
 11	  Button,
 12	  TextInput,
 13	  InputGroup,
 14	  InputGroupItem,
 15	} from '@patternfly/react-core';
 16	import { AWS_REGIONS, StoreProviders, StoreType } from '../../constants';
 17	import './noobaa-provider-endpoints.scss';
 18	import { awsRegionItems, endpointsSupported } from '../../utils';
 19	
 20	export type ProviderDataState = {
 21	  secretName: string;
 22	  secretKey: string;
 23	  accessKey: string;
 24	  region: string;
 25	  target: string;
 26	  endpoint: string;
 27	};
 28	
 29	export type StoreAction =
 30	  | { type: 'setSecretName'; value: string }
 31	  | { type: 'setSecretKey'; value: string }
 32	  | { type: 'setAccessKey'; value: string }
 33	  | { type: 'setRegion'; value: string }
 34	  | { type: 'setTarget'; value: string }
 35	  | { type: 'setEndpoint'; value: string };
 36	
 37	type S3EndpointTypeProps = {
 38	  type: StoreType;
 39	  state: ProviderDataState;
 40	  dispatch: React.Dispatch<StoreAction>;
 41	  provider: StoreProviders;
 42	  namespace: string;
 43	  control: Control;
 44	  showSecret: boolean;
 45	  setShowSecret: (showSecret: boolean) => void;
 46	};
 47	
 48	export const S3EndPointType: React.FC<S3EndpointTypeProps> = (props) => {
 49	  const { t } = useCustomTranslation();
 50	
 51	  const {
 52	    provider,
 53	    namespace,
 54	    state,
 55	    dispatch,
 56	    type,
 57	    control,
 58	    showSecret,
 59	    setShowSecret,
 60	  } = props;
 61	
 62	  const targetLabel =
 63	    provider === StoreProviders.AZURE
 64	      ? t('Target blob container')
 65	      : t('Target bucket');
 66	  const credentialField1Label =
 67	    provider === StoreProviders.AZURE ? t('Account name') : t('Access key');
 68	  const credentialField2Label =
 69	    provider === StoreProviders.AZURE ? t('Account key') : t('Secret key');
 70	
 71	  const switchToSecret = () => {
 72	    setShowSecret(true);
 73	    dispatch({ type: 'setAccessKey', value: '' });
 74	    dispatch({ type: 'setSecretKey', value: '' });
 75	  };
 76	
 77	  const switchToCredentials = () => {
 78	    setShowSecret(false);
 79	    dispatch({ type: 'setSecretName', value: '' });
 80	  };
 81	
 82	  return (
 83	    <>
 84	      {provider === StoreProviders.AWS && (
 85	        <FormGroupController
 86	          name="aws-region"
 87	          control={control}
 88	          formGroupProps={{
 89	            label: t('Region'),
 90	            fieldId: 'region',
 91	            className: 'nb-endpoints-form-entry',
 92	            isRequired: true,
 93	          }}
 94	          defaultValue={AWS_REGIONS[0]}
 95	          render={({ value, onChange, onBlur }) => (
 96	            <StaticDropdown
 97	              className="nb-endpoints-form-entry__dropdown"
 98	              onSelect={(key) => {
 99	                onChange(key);
100	                dispatch({ type: 'setRegion', value: key });
101	              }}
102	              onBlur={onBlur}
103	              dropdownItems={awsRegionItems}
104	              defaultSelection={value}
105	              aria-label={t('Region Dropdown')}
106	              data-test="aws-region-dropdown"
107	              isFullWidth
108	            />
109	          )}
110	        />
111	      )}
112	
113	      {endpointsSupported.includes(provider) && (
114	        <FormGroupController
115	          name="endpoint"
116	          control={control}
117	          formGroupProps={{
118	            label: t('Endpoint'),
119	            fieldId: 'endpoint',
120	            className: 'nb-endpoints-form-entry',
121	            isRequired: true,
122	          }}
123	          defaultValue={state.endpoint}
124	          render={({ value, onChange, onBlur }) => (
125	            <TextInput
126	              data-test={`${type.toLowerCase()}-s3-endpoint`}
127	              onChange={(e, val) => {
128	                onChange(e);
129	                dispatch({ type: 'setEndpoint', value: val });
130	              }}
131	              onBlur={onBlur}
132	              id="endpoint"
133	              value={value}
134	              aria-label={t('Endpoint Address')}
135	            />
136	          )}
137	        />
138	      )}
139	
140	      {showSecret ? (
141	        <FormGroupController
142	          name="secret"
143	          control={control}
144	          formGroupProps={{
145	            label: t('Secret'),
146	            fieldId: 'secret-dropdown',
147	            className:
148	              'nb-endpoints-form-entry nb-endpoints-form-entry--full-width',
149	            isRequired: true,
150	          }}
151	          render={({ onChange, onBlur }) => (
152	            <InputGroup>
153	              <InputGroupItem>
154	                <ResourceDropdown<SecretKind>
155	                  className="nb-endpoints-form-entry__dropdown nb-endpoints-form-entry__dropdown--full-width"
156	                  onSelect={(res) => {
157	                    const value = getName(res);
158	                    onChange(value);
159	                    dispatch({ type: 'setSecretName', value });
160	                  }}
161	                  onBlur={onBlur}
162	                  resource={{
163	                    kind: SecretModel.kind,
164	                    isList: true,
165	                    namespace,
166	                  }}
167	                  resourceModel={SecretModel}
168	                />
169	              </InputGroupItem>
170	              <InputGroupItem>
171	                <Button
172	                  variant="plain"
173	                  data-test="switch-to-creds"
174	                  onClick={switchToCredentials}
175	                >
176	                  {t('Switch to Credentials')}
177	                </Button>
178	              </InputGroupItem>
179	            </InputGroup>
180	          )}
181	        />
182	      ) : (
183	        <>
184	          <FormGroupController
185	            name="access-key"
186	            control={control}
187	            defaultValue={state.accessKey}
188	            formGroupProps={{
189	              label: credentialField1Label,
190	              fieldId: 'access-key',
191	            }}
192	            render={({ value, onChange, onBlur }) => (
193	              <InputGroup>
194	                <InputGroupItem isFill>
195	                  <TextInput
196	                    id="access-key"
197	                    data-test={`${type.toLowerCase()}-access-key`}
198	                    value={value}
199	                    onChange={(e, val) => {
200	                      onChange(e);
201	                      dispatch({ type: 'setAccessKey', value: val });
202	                    }}
203	                    onBlur={onBlur}
204	                    aria-label={t('Access Key Field')}
205	                  />
206	                </InputGroupItem>
207	                <InputGroupItem>
208	                  <Button variant="plain" onClick={switchToSecret}>
209	                    {t('Switch to Secret')}
210	                  </Button>
211	                </InputGroupItem>
212	              </InputGroup>
213	            )}
214	          />
215	          <FormGroupController
216	            name="secret-key"
217	            control={control}
218	            defaultValue={state.secretKey}
219	            formGroupProps={{
220	              className: 'nb-endpoints-form-entry',
221	              label: credentialField2Label,
222	              fieldId: 'secret-key',
223	            }}
224	            render={({ value, onChange, onBlur }) => (
225	              <TextInput
226	                value={value}
227	                id="secret-key"
228	                data-test={`${type.toLowerCase()}-secret-key`}
229	                onChange={(e, val) => {
230	                  onChange(e);
231	                  dispatch({ type: 'setSecretKey', value: val });
232	                }}
233	                onBlur={onBlur}
234	                aria-label={t('Secret Key Field')}
235	                type="password"
236	              />
237	            )}
238	          />
239	        </>
240	      )}
241	      <FormGroupController
242	        name="target-bucket"
243	        control={control}
244	        defaultValue={state.target}
245	        formGroupProps={{
246	          label: targetLabel,
247	          fieldId: 'target-bucket',
248	          className: 'nb-endpoints-form-entry',
249	          isRequired: true,
250	        }}
251	        render={({ value, onChange, onBlur }) => (
252	          <TextInput
253	            id="target-bucket"
254	            value={value}
255	            data-test={`${type.toLowerCase()}-target-bucket`}
256	            onChange={(e, val) => {
257	              onChange(e);
258	              dispatch({ type: 'setTarget', value: val });
259	            }}
260	            onBlur={onBlur}
261	            aria-label={targetLabel}
262	          />
263	        )}
264	      />
265	    </>
266	  );
267	};

